insert into public.case_king_questions
  (id, case_no, question, answer, source, url, type)
values
(1,'민법 표준판례 1. 민법의 법원：관습법 대법원 2003. 7. 24. 선고 2001다48781 전원합의체 판결','사회의 거듭된 관행으로 생성한 어떤 사회생활규범이 법적 규범으로 승인되기에 이르렀다고 하기 위하여는 그 사회생활규범은 헌법을 최상위 규범으로 하는 전체 법질서에 반하지 아니하는 것으로서 정당성과 합리성이 있다고 인정될 수 있는 것이어야 하고, 그렇지 아니한 사회생활규범은 비록 그것이 사회의 거듭된 관행으로 생성된 것이라고 할지라도 이를 법적 규범으로 삼아 (A) 으로서의 효력을 인정할 수 없는바, 제정 민법이 시행되기 전에 존재하던 관습 중 “ 상속회복청구권 은 상속이 개시된 날부터 20년이 경과하면 소멸한다. ”는 내용의 관습은 이를 적용하게 되면 20 년 의 경과 후에 상속권침해가 있을 때에는 침해행위와 동시에 진정상속인은 권리를 잃고 구제를 받 을 수 없는 결과가 되므로 소유권은 원래 소멸시효의 적용을 받지 않는다는 권리의 속성에 반할 뿐 아니라 진정상속인으로 하여금 참칭상속인에 의한 재산권침해를 사실상 방어할 수 없게 만드는 결과로 되어 불합리하고, 헌법을 최상위 규범으로 하는 법질서 전체의 이념에도 부합하지 아니하여 정당성이 없으므로, 위 관습에 법적 규범인 관습법으로서의 효력을 인정할 수 없다.','관습법','민법 표준판례 1. 민법의 법원：관습법 대법원 2003. 7. 24. 선고 2001다48781 전원합의체 판결','','판례검색'),
(2,'민법 표준판례 1. 민법의 법원：관습법 대법원 2003. 7. 24. 선고 2001다48781 전원합의체 판결','사회의 거듭된 관행으로 생성한 어떤 사회생활규범이 법적 규범으로 승인되기에 이르렀다고 하기 위하여는 그 사회생활규범은 헌법을 최상위 규범으로 하는 전체 법질서에 반하지 아니하는 것으로서 정당성과 합리성이 있다고 인정될 수 있는 것이어야 하고, 그렇지 아니한 사회생활규범은 비록 그것이 사회의 거듭된 관행으로 생성된 것이라고 할지라도 이를 법적 규범으로 삼아 관습법 으로서의 효력을 인정할 수 없는바, 제정 민법이 시행되기 전에 존재하던 관습 중 “ (A) 은 상속이 개시된 날부터 20년이 경과하면 소멸한다. ”는 내용의 관습은 이를 적용하게 되면 20 년 의 경과 후에 상속권침해가 있을 때에는 침해행위와 동시에 진정상속인은 권리를 잃고 구제를 받 을 수 없는 결과가 되므로 소유권은 원래 소멸시효의 적용을 받지 않는다는 권리의 속성에 반할 뿐 아니라 진정상속인으로 하여금 참칭상속인에 의한 재산권침해를 사실상 방어할 수 없게 만드는 결과로 되어 불합리하고, 헌법을 최상위 규범으로 하는 법질서 전체의 이념에도 부합하지 아니하여 정당성이 없으므로, 위 관습에 법적 규범인 관습법으로서의 효력을 인정할 수 없다.','상속회복청구권','민법 표준판례 1. 민법의 법원：관습법 대법원 2003. 7. 24. 선고 2001다48781 전원합의체 판결','','판례검색'),
(3,'형법 표준판례 1. 법률주의, 위임입법 헌법재판소 1991. 7. 8. 선고 91헌가4 전원재판부; 대법원 2013. 6. 13. 선고 2013도168 5 판결','91헌가4：‘(A)’라는 말로 표현되는 죄형법정주의는 이미 제 정된 정의로운 법률에 의하지 아니하고는 처벌되지 아니한다는 원칙으로서 이는 무엇이 처벌될 행 위인가를 국민이 예측가능한 형식으로 정하도록 하여 개인의 법적 안정성을 보호하고 성문의 형벌 법규에 의한 실정법질서를 확립하여 국가형벌권의 자의적(恣意的) 행사로부터 개인의 자유와 권리 를 보장하려는 법치국가 형법의 기본원칙이다. 형벌법규에서 위임입법은 죄형법정주의의 법률주의에 반하는지, 허용된다면 어떤 범위에서 허용 되는지 문제된다. 형벌법규는 국민의 자유와 권리에 심각한 효과를 주므로, 형벌법규에서 법률의 위임은 미리 법률로써 자세히 정할 수 없는 부득이한 사정이 있는 경우에 한정되어야 하고 이러한 경우일지라도 법률에서 범죄의 구성요건은 처벌대상인 행위가 어떠한 것일 것이라고 이를 예측할 수 있을 정도로 구체적으로 정하고 형벌의 종류 및 그 상한과 폭을 명백히 규정하여야 한다. → 복표발행·현상기타사행 행위단속법(福票發行·懸賞其他射倖行爲團束法)(1991. 3.','법률이 없으면 범죄도 없고 형벌도 없다','형법 표준판례 1. 법률주의, 위임입법 헌법재판소 1991. 7. 8. 선고 91헌가4 전원재판부; 대법원 2013. 6. 13. 선고 2013도168 5 판결','','판례검색'),
(4,'민법 표준판례 2. 민법의 법원：관습법 대법원 2005. 7. 21. 선고 2002다1178 전원합의체 판결','관습법이란 사회의 거듭된 관행으로 생성한 사회생활규범이 사회의 법적 확신과 인식에 의하 여 법적 규범으로 (A)·강행되기에 이른 것을 말하고, 그러한 관습법은 법원(法源)으로서 법령에 저촉되지 아니하는 한 법칙으로서의 효력이 있는 것이고, 또 사회의 거듭된 관행으로 생성한 어떤 사회생활규범이 법적 규범으로 승인되기에 이르렀다고 하기 위하여는 헌법을 최상위 규범으로 하 는 전체 법질서에 반하지 아니하는 것으로서 정당성과 합리성이 있다고 인정될 수 있는 것이어야 하고, 그렇지 아니한 사회생활규범은 비록 그것이 사회의 거듭된 관행으로 생성된 것이라고 할지라 도 이를 법적 규범으로 삼아 관습법으로서의 효력을 인정할 수 없다. 사회의 거듭된 관행으로 생성된 사회생활규범이 관습법으로 승인되었다고 하더라도 사회 구 성원들이 그러한 관행의 법적 구속력에 대하여 확신을 갖지 않게 되었다거나, 사회를 지배하는 기 본적 이념이나 사회질서의 변화로 인하여 그러한 관습법을 적용하여야 할 시점에 있어서의 전체 법질서에 부합하지 않게 되었다면 그러한 관습법은 법적 규범으로서의 효력이 부정될 수밖에 없다. 종원의 자격을 성년 남자로만 제한하고 여성에게는 종원의 자격을 부여하지 않는 종래 관습 에 대하여 우리 사회 구성원들이 가지고 있던 법적 확신은 상당 부분 흔들리거나 약화되어 있고, 무엇보다도 헌법을 최상위 규범으로 하는 우리의 전체 법질서는 개인의 존엄과 양성의 평등을 기 초로 한 가족생활을 보장하고, 가족 내의 실질적인 권리와 의무에 있어서 남녀의 차별을 두지 아 니하며, 정치·경제·사회·문화 등 모든 영역에서 여성에 대한 차별을 철폐하고 남녀평등을 실현하는 방향으로 변화되어 왔으며, 앞으로도 이러한 남녀평등의 원칙은 더욱 강화될 것인바, 종중은 공동 선조의 분묘수호와 봉제사 및 종원 상호간의 친목을 목적으로 형성되는 종족단체로서 공동선조의 사망과 동시에 그 후손에 의하여 자연발생적으로 성립하는 것임에도, 공동선조의 후손 중 성년 남 자만을 종중의 구성원으로 하고 여성은 종중의 구성원이 될 수 없다는 종래의 관습은, 공동선조의 분묘수호와 봉제사 등 종중의 활동에 참여할 기회를 출생에서 비롯되는 성별만에 의하여 생래적으 로 부여하거나 원천적으로 박탈하는 것으로서, 위와 같이 변화된 우리의 전체 법질서에 부합하지 아니하여 정당성과 합리성이 있다고 할 수 없으므로, 종중 구성원의 자격을 성년 남자만으로 제한 하는 종래의 관습법은 이제 더 이상 법적 효력을 가질 수 없게 되었다. 종중이란 공동선조의 분묘수호와 제사 및 종원 상호간의 친목 등을 목적으로 하여 구성되는 자연발생적인 종족집단이므로, 종중의 이러한 목적과 본질에 비추어 볼 때 공동선조와 성과 본을 같이 하는 후손은 성별의 구별 없이 성년이 되면 당연히 그 구성원이 된다고 보는 것이 조리에 합 당하다. 종중 구성원의 자격에 관한 대법원의 견해의 변경은 관습상의 제도로서 대법원판례에 의하여 법률관계가 규율되어 왔던 종중제도의 근간을 바꾸는 것인바, 대법원이 이 판결에서 종중 구성원의 자격에 관하여 ‘공동선조와 성과 본을 같이 하는 후손은 성별의 구별 없이 성년이 되면 당연히 그 구성원이 된다.','승인','민법 표준판례 2. 민법의 법원：관습법 대법원 2005. 7. 21. 선고 2002다1178 전원합의체 판결','','판례검색'),
(5,'형법 표준판례 1. 법률주의, 위임입법 헌법재판소 1991. 7. 8. 선고 91헌가4 전원재판부; 대법원 2013. 6. 13. 선고 2013도168 5 판결','→ 복표발행·현상기타사행 행위단속법(福票發行·懸賞其他射倖行爲團束法)(1991. 3. 8. 법률 제4339 호 사행행위(射倖行爲)등규제법으로 개정되기 전의 것) 제9조는 벌칙규정이면서도 형벌만을 규정하고 범죄의 구성요건의 설정은 완전히 각령(閣令)에 백지위임(白紙委任)하고 있는 것이나 다름없어 (A) 입법(委任立法)의 한계를 규정한 헌법 제75조와 죄형법정주의를 규정한 헌법 제12조 제1항, 제 13 조 제1항에 위반(違反)된다. 2013도1695： 사회현상의 복잡다기화와 국회의 전문적·기술적 능력의 한계 및 시간경과에 대한 적응능력의 한계로 인하여 형사처벌에 관련된 모든 법규를 예외 없이 형식적 의미의 법률에 의하 여 규정한다는 것은 사실상 불가능할 뿐만 아니라 실제에 적합하지도 아니하기 때문에, 입법자의 상세한 규율이 불가능하거나 상황의 변화에 탄력적으로 대응할 필요성이 강하게 요구되는 경우에 는 위임법률이 구성요건의 점에서는 처벌대상인 행위가 어떠한 것인지 이를 예측할 수 있을 정도 로 구체적으로 정하고, 형벌의 점에서는 형벌의 종류 및 그 상한과 폭을 명확히 규정하는 것을 전 제로 위임입법이 허용된다(대법원 2006.','위임','형법 표준판례 1. 법률주의, 위임입법 헌법재판소 1991. 7. 8. 선고 91헌가4 전원재판부; 대법원 2013. 6. 13. 선고 2013도168 5 판결','','판례검색'),
(6,'형법 표준판례 1. 법률주의, 위임입법 헌법재판소 1991. 7. 8. 선고 91헌가4 전원재판부; 대법원 2013. 6. 13. 선고 2013도168 5 판결','→ 복표발행·현상기타사행 행위단속법(福票發行·懸賞其他射倖行爲團束法)(1991. 3. 8. 법률 제4339 호 (A)(射倖行爲)등규제법으로 개정되기 전의 것) 제9조는 벌칙규정이면서도 형벌만을 규정하고 범죄의 구성요건의 설정은 완전히 각령(閣令)에 백지위임(白紙委任)하고 있는 것이나 다름없어 위임 입법(委任立法)의 한계를 규정한 헌법 제75조와 죄형법정주의를 규정한 헌법 제12조 제1항, 제 13 조 제1항에 위반(違反)된다. 2013도1695： 사회현상의 복잡다기화와 국회의 전문적·기술적 능력의 한계 및 시간경과에 대한 적응능력의 한계로 인하여 형사처벌에 관련된 모든 법규를 예외 없이 형식적 의미의 법률에 의하 여 규정한다는 것은 사실상 불가능할 뿐만 아니라 실제에 적합하지도 아니하기 때문에, 입법자의 상세한 규율이 불가능하거나 상황의 변화에 탄력적으로 대응할 필요성이 강하게 요구되는 경우에 는 위임법률이 구성요건의 점에서는 처벌대상인 행위가 어떠한 것인지 이를 예측할 수 있을 정도 로 구체적으로 정하고, 형벌의 점에서는 형벌의 종류 및 그 상한과 폭을 명확히 규정하는 것을 전 제로 위임입법이 허용된다(대법원 2006.','사행행위','형법 표준판례 1. 법률주의, 위임입법 헌법재판소 1991. 7. 8. 선고 91헌가4 전원재판부; 대법원 2013. 6. 13. 선고 2013도168 5 판결','','판례검색'),
(7,'형법 표준판례 1. 법률주의, 위임입법 헌법재판소 1991. 7. 8. 선고 91헌가4 전원재판부; 대법원 2013. 6. 13. 선고 2013도168 5 판결','법률 제4339 호 사행행위(射倖行爲)등규제법으로 개정되기 전의 것) 제9조는 벌칙규정이면서도 형벌만을 규정하고 범죄의 구성요건의 설정은 완전히 각령(閣令)에 백지위임(白紙委任)하고 있는 것이나 다름없어 (A) 입법(委任立法)의 한계를 규정한 헌법 제75조와 죄형법정주의를 규정한 헌법 제12조 제1항, 제 13 조 제1항에 위반(違反)된다. 2013도1695： 사회현상의 복잡다기화와 국회의 전문적·기술적 능력의 한계 및 시간경과에 대한 적응능력의 한계로 인하여 형사처벌에 관련된 모든 법규를 예외 없이 형식적 의미의 법률에 의하 여 규정한다는 것은 사실상 불가능할 뿐만 아니라 실제에 적합하지도 아니하기 때문에, 입법자의 상세한 규율이 불가능하거나 상황의 변화에 탄력적으로 대응할 필요성이 강하게 요구되는 경우에 는 위임법률이 구성요건의 점에서는 처벌대상인 행위가 어떠한 것인지 이를 예측할 수 있을 정도 로 구체적으로 정하고, 형벌의 점에서는 형벌의 종류 및 그 상한과 폭을 명확히 규정하는 것을 전 제로 위임입법이 허용된다(대법원 2006. 1. 13. 선고 2005도7474 판결, 대법원 2010.','위임','형법 표준판례 1. 법률주의, 위임입법 헌법재판소 1991. 7. 8. 선고 91헌가4 전원재판부; 대법원 2013. 6. 13. 선고 2013도168 5 판결','','판례검색'),
(8,'형법 표준판례 1. 법률주의, 위임입법 헌법재판소 1991. 7. 8. 선고 91헌가4 전원재판부; 대법원 2013. 6. 13. 선고 2013도168 5 판결','법률 제4339 호 (A)(射倖行爲)등규제법으로 개정되기 전의 것) 제9조는 벌칙규정이면서도 형벌만을 규정하고 범죄의 구성요건의 설정은 완전히 각령(閣令)에 백지위임(白紙委任)하고 있는 것이나 다름없어 위임 입법(委任立法)의 한계를 규정한 헌법 제75조와 죄형법정주의를 규정한 헌법 제12조 제1항, 제 13 조 제1항에 위반(違反)된다. 2013도1695： 사회현상의 복잡다기화와 국회의 전문적·기술적 능력의 한계 및 시간경과에 대한 적응능력의 한계로 인하여 형사처벌에 관련된 모든 법규를 예외 없이 형식적 의미의 법률에 의하 여 규정한다는 것은 사실상 불가능할 뿐만 아니라 실제에 적합하지도 아니하기 때문에, 입법자의 상세한 규율이 불가능하거나 상황의 변화에 탄력적으로 대응할 필요성이 강하게 요구되는 경우에 는 위임법률이 구성요건의 점에서는 처벌대상인 행위가 어떠한 것인지 이를 예측할 수 있을 정도 로 구체적으로 정하고, 형벌의 점에서는 형벌의 종류 및 그 상한과 폭을 명확히 규정하는 것을 전 제로 위임입법이 허용된다(대법원 2006. 1. 13. 선고 2005도7474 판결, 대법원 2010.','사행행위','형법 표준판례 1. 법률주의, 위임입법 헌법재판소 1991. 7. 8. 선고 91헌가4 전원재판부; 대법원 2013. 6. 13. 선고 2013도168 5 판결','','판례검색'),
(9,'형법 표준판례 2. 명확성의 원칙 헌법재판소 2006. 7. 27. 선고 2005헌바19 전원재판부','처벌법규의 구성요건이 명확하여야 한다고 하더라도 입법권자가 모두 구성요건을 단순한 의미의 서술적인 개념에 의하여 규정하여야 한다는 것은 아니다. 처벌법규의 구성요건이 다소 광범위하여 어떤 범위에서는 법관의 보충적인 해석을 필요로 하는 개념을 사용하였다고 하더라도 그 점만으로 헌법이 요구하는 처벌법규의 명확성의 원칙에 반드시 배치되는 것이라고 볼 수 없다. 즉 건전한 상식과 통상적인 법감정을 가진 사람으로 하여금 그 적용대상자가 누구이며 구체적으로 어떠한 행 위가 금지되고 있는지 충분히 알 수 있도록 규정되어 있다면 죄형법정주의의 명확성의 원칙에 위 배되지 않는다고 보아야 한다. ‘궁박’이나 ‘(A)’이라는 개념도 형법상의 ‘지려천박(知慮淺薄)’, ‘기망’, ‘ 임무에 위배’ 등과 같이 범죄구성요건을 형성하는 개념 중 구체적 사안에 있어서 일정한 해석을 통하여 적용할 수 있는 일반적, 규범적 개념의 하나로서, ‘궁박한 상태를 이용하여 현저하게 부당한 이익 을 취득’하였는지 여부는 사회통념 또는 건전한 상식에 따라 거래당사자의 신분과 상호 간의 관계, 피해자가 처한 상황의 절박성의 정도, 계약의 체결을 둘러싼 협상과정 및 피해자의 이익, 피해자가 그 거래를 통해 추구하고자 한 목적을 달성하기 위한 다른 적절한 대안의 존재 여부 등 제반 상황 을 종합한다면 합리적으로 판단할 수 있다고 할 것이므로 이 사건 법률조항이 지니는 약간의 불명 확성은 법관의 통상적인 해석 작용에 의하여 충분히 보완될 수 있고 건전한 상식과 통상적인 법감 정을 가진 일반인이라면 금지되는 행위가 무엇인지를 예측할 수 있으므로 이 사건 법률조항은 죄 형법 총론 제 1 편 서 론 형법정주의에서 요구되는 명확성의 원칙에 위배되지 아니한다.','현저하게 부당한 이익','형법 표준판례 2. 명확성의 원칙 헌법재판소 2006. 7. 27. 선고 2005헌바19 전원재판부','','판례검색'),
(10,'형법 표준판례 2. 명확성의 원칙 헌법재판소 2006. 7. 27. 선고 2005헌바19 전원재판부','처벌법규의 구성요건이 명확하여야 한다고 하더라도 입법권자가 모두 구성요건을 단순한 의미의 서술적인 개념에 의하여 규정하여야 한다는 것은 아니다. 처벌법규의 구성요건이 다소 광범위하여 어떤 범위에서는 법관의 보충적인 해석을 필요로 하는 개념을 사용하였다고 하더라도 그 점만으로 헌법이 요구하는 처벌법규의 명확성의 원칙에 반드시 배치되는 것이라고 볼 수 없다. 즉 건전한 상식과 통상적인 법감정을 가진 사람으로 하여금 그 적용대상자가 누구이며 구체적으로 어떠한 행 위가 금지되고 있는지 충분히 알 수 있도록 규정되어 있다면 죄형법정주의의 명확성의 원칙에 위 배되지 않는다고 보아야 한다. ‘궁박’이나 ‘현저하게 부당한 이익’이라는 개념도 형법상의 ‘지려천박(知慮淺薄)’, ‘기망’, ‘ 임무에 위배’ 등과 같이 범죄구성요건을 형성하는 개념 중 구체적 사안에 있어서 일정한 해석을 통하여 적용할 수 있는 일반적, 규범적 개념의 하나로서, ‘궁박한 상태를 이용하여 (A) 을 취득’하였는지 여부는 사회통념 또는 건전한 상식에 따라 거래당사자의 신분과 상호 간의 관계, 피해자가 처한 상황의 절박성의 정도, 계약의 체결을 둘러싼 협상과정 및 피해자의 이익, 피해자가 그 거래를 통해 추구하고자 한 목적을 달성하기 위한 다른 적절한 대안의 존재 여부 등 제반 상황 을 종합한다면 합리적으로 판단할 수 있다고 할 것이므로 이 사건 법률조항이 지니는 약간의 불명 확성은 법관의 통상적인 해석 작용에 의하여 충분히 보완될 수 있고 건전한 상식과 통상적인 법감 정을 가진 일반인이라면 금지되는 행위가 무엇인지를 예측할 수 있으므로 이 사건 법률조항은 죄 형법 총론 제 1 편 서 론 형법정주의에서 요구되는 명확성의 원칙에 위배되지 아니한다.','현저하게 부당한 이익','형법 표준판례 2. 명확성의 원칙 헌법재판소 2006. 7. 27. 선고 2005헌바19 전원재판부','','판례검색'),
(11,'형법 표준판례 3. 유추적용금지 대법원 2017. 12. 21. 선고 2015도8335 전원합의체 판결','항공보안법 제42조는 “위계 또는 위력으로써 운항 중인 항공기의 항로를 변경하게 하여 정상 운 항을 방해한 사람은 1년 이상 10년 이하의 징역에 처한다. ”라고 규정하고 있다. 같은 법 제2조 제 1호는 ‘(A)’을 ‘승객이 탑승한 후 항공기의 모든 문이 닫힌 때로부터 내리기 위하여 문을 열 때까지’로 정의하였다. 그러나 항공보안법에 ‘항로’가 무엇인지에 관하여 정의한 규정은 없다. 죄형법정주의는 국가형벌권의 자의적인 행사로부터 개인의 자유와 권리를 보호하기 위하여 범죄 와 형벌을 법률로 정할 것을 요구한다.','운항 중','형법 표준판례 3. 유추적용금지 대법원 2017. 12. 21. 선고 2015도8335 전원합의체 판결','','판례검색'),
(12,'헌법 표준판례 5. 헌법해석의 기준과 내용','헌법의 전문과 본문의 전체에 담겨있는 (A) 이념은 국민주권주의와 자유민주주에 입각한 입헌 민주헌법의 본질적 기본원리에 기초한다. 그 밖에 헌법상 모든 원칙도 여기에서 연유되는 것이므로 이는 헌법전을 비롯한 모든 법령해석의 기준이 되고, 입법형성권 행사의 한계와 정책결정의 방향을 제시하며, 나아가 모든 국가기관과 국민이 존중하고 지켜가야 하는 최고의 가치규범이다. 헌법은 국민적 합의로 제정된 국민생활의 최고 도덕규범이며 정치생활의 가치규범으로서 정치와 사회질서 의 지침을 제공하므로 민주사회에서는 헌법의 규범을 준수하고 그 권위를 보존하는 것을 기본으로 한다. 헌법의 해석은 헌법이 담고 추구하는 이상과 이념에 따른 역사적ㆍ사회적 요구를 올바르게 수용하여 헌법적 방향을 제시하는 헌법의 창조적 기능을 수행하여 국민적 욕구와 의식에 알맞은 실질적 국민주권의 실현을 보장하는 것이어야 한다.','최고','헌법 표준판례 5. 헌법해석의 기준과 내용','','판례검색'),
(13,'헌법 표준판례 5. 헌법해석의 기준과 내용','헌법의 전문과 본문의 전체에 담겨있는 최고 이념은 국민주권주의와 자유민주주에 입각한 입헌 민주헌법의 본질적 기본원리에 기초한다. 그 밖에 헌법상 모든 원칙도 여기에서 연유되는 것이므로 이는 헌법전을 비롯한 모든 법령해석의 기준이 되고, 입법형성권 행사의 한계와 정책결정의 방향을 제시하며, 나아가 모든 국가기관과 국민이 존중하고 지켜가야 하는 최고의 가치규범이다. 헌법은 국민적 합의로 제정된 국민생활의 (A) 도덕규범이며 정치생활의 가치규범으로서 정치와 사회질서 의 지침을 제공하므로 민주사회에서는 헌법의 규범을 준수하고 그 권위를 보존하는 것을 기본으로 한다. 헌법의 해석은 헌법이 담고 추구하는 이상과 이념에 따른 역사적ㆍ사회적 요구를 올바르게 수용하여 헌법적 방향을 제시하는 헌법의 창조적 기능을 수행하여 국민적 욕구와 의식에 알맞은 실질적 국민주권의 실현을 보장하는 것이어야 한다.','최고','헌법 표준판례 5. 헌법해석의 기준과 내용','','판례검색'),
(14,'민법 표준판례 6. 신의성실의 원칙：강행법규 위반과의 관계 대법원 2000. 6. 9. 선고 99다70860 판결','사립학교법 제28조 제2항, 같은법시행령 제12조가 학교법인이 학교교육에 직접 사용되는 학교법 인의 재산 중 교지, 교사 등은 이를 매도하거나 담보에 제공할 수 없다고 규정한 것은 사립학교의 존립 및 목적 수행에 필수적인 교육시설을 보전함으로써 사립학교의 건전한 발달을 도모하는 데 그 목적이 있는 것이라고 해석되는바, 강행법규인 같은 법 제28조 제2항을 위반한 경우에 위반한 자 스스로가 무효를 주장함이 (A) 내지 신의성실원칙에 위배되는 권리의 행사라는 이유로 배 척된다면 위와 같은 입법 취지를 완전히 몰각시키는 결과가 되므로 명목상으로만 학교법인에 직접 사용되는 재산으로 되어 있을 뿐 실제로는 학교교육에 직접 사용되는 시설·설비 및 교재·교구 등 이 아니거나 학교 자체가 형해화되어 사실상 교육시설로 볼 수 없는 경우와 같은 특별한 사정이 있다면 매도나 담보제공을 무효라고 주장하는 것은 법규정의 취지에 반하는 것이므로 신의성실 원 칙에 반하거나 권리남용이라고 볼 것이지만 그와 같은 특별한 사정이 없이 사립학교 경영자가 매 도나 담보제공이 무효라는 사실을 알고서 매도나 담보제공을 하였다고 하더라도 매도나 담보제공 을 금한 관련 법규정의 입법 취지에 비추어 강행규정 위배로 인한 무효주장을 신의성실 원칙에 반 하거나 권리남용이라고 볼 것은 아니다.','권리남용','민법 표준판례 6. 신의성실의 원칙：강행법규 위반과의 관계 대법원 2000. 6. 9. 선고 99다70860 판결','','판례검색'),
(15,'민법 표준판례 6. 신의성실의 원칙：강행법규 위반과의 관계 대법원 2000. 6. 9. 선고 99다70860 판결','사립학교법 제28조 제2항, 같은법시행령 제12조가 학교법인이 학교교육에 직접 사용되는 학교법 인의 재산 중 교지, 교사 등은 이를 매도하거나 담보에 제공할 수 없다고 규정한 것은 사립학교의 존립 및 목적 수행에 필수적인 교육시설을 보전함으로써 사립학교의 건전한 발달을 도모하는 데 그 목적이 있는 것이라고 해석되는바, 강행법규인 같은 법 제28조 제2항을 위반한 경우에 위반한 자 스스로가 무효를 주장함이 권리남용 내지 신의성실원칙에 위배되는 권리의 행사라는 이유로 배 척된다면 위와 같은 입법 취지를 완전히 몰각시키는 결과가 되므로 명목상으로만 학교법인에 직접 사용되는 재산으로 되어 있을 뿐 실제로는 학교교육에 직접 사용되는 시설·설비 및 교재·교구 등 이 아니거나 학교 자체가 형해화되어 사실상 교육시설로 볼 수 없는 경우와 같은 특별한 사정이 있다면 매도나 담보제공을 무효라고 주장하는 것은 법규정의 취지에 반하는 것이므로 (A) 원 칙에 반하거나 권리남용이라고 볼 것이지만 그와 같은 특별한 사정이 없이 사립학교 경영자가 매 도나 담보제공이 무효라는 사실을 알고서 매도나 담보제공을 하였다고 하더라도 매도나 담보제공 을 금한 관련 법규정의 입법 취지에 비추어 강행규정 위배로 인한 무효주장을 신의성실 원칙에 반 하거나 권리남용이라고 볼 것은 아니다.','신의성실','민법 표준판례 6. 신의성실의 원칙：강행법규 위반과의 관계 대법원 2000. 6. 9. 선고 99다70860 판결','','판례검색'),
(16,'민법 표준판례 6. 신의성실의 원칙：강행법규 위반과의 관계 대법원 2000. 6. 9. 선고 99다70860 판결','사립학교법 제28조 제2항, 같은법시행령 제12조가 학교법인이 학교교육에 직접 사용되는 학교법 인의 재산 중 교지, 교사 등은 이를 매도하거나 담보에 제공할 수 없다고 규정한 것은 사립학교의 존립 및 목적 수행에 필수적인 교육시설을 보전함으로써 사립학교의 건전한 발달을 도모하는 데 그 목적이 있는 것이라고 해석되는바, 강행법규인 같은 법 제28조 제2항을 위반한 경우에 위반한 자 스스로가 무효를 주장함이 권리남용 내지 신의성실원칙에 위배되는 권리의 행사라는 이유로 배 척된다면 위와 같은 입법 취지를 완전히 몰각시키는 결과가 되므로 명목상으로만 학교법인에 직접 사용되는 재산으로 되어 있을 뿐 실제로는 학교교육에 직접 사용되는 시설·설비 및 교재·교구 등 이 아니거나 학교 자체가 형해화되어 사실상 교육시설로 볼 수 없는 경우와 같은 특별한 사정이 있다면 매도나 담보제공을 무효라고 주장하는 것은 법규정의 취지에 반하는 것이므로 신의성실 원 칙에 반하거나 권리남용이라고 볼 것이지만 그와 같은 특별한 사정이 없이 사립학교 경영자가 매 도나 담보제공이 무효라는 사실을 알고서 매도나 담보제공을 하였다고 하더라도 매도나 담보제공 을 금한 관련 법규정의 입법 취지에 비추어 강행규정 위배로 인한 무효주장을 (A) 원칙에 반 하거나 권리남용이라고 볼 것은 아니다.','신의성실','민법 표준판례 6. 신의성실의 원칙：강행법규 위반과의 관계 대법원 2000. 6. 9. 선고 99다70860 판결','','판례검색'),
(17,'형법 표준판례 5. 진정ㆍ부진정 소급효 헌법재판소 1996. 2. 16. 선고 96헌가2 전원재판부','3. 형벌불소급의 원칙은 “(A)” 즉 형사소추가 “언제부터 어떠한 조건하에서” 가능한가 의 문제에 관한 것이고, “얼마동안” 가능한가의 문제에 관한 것은 아니므로, 과거에 이미 행한 범 죄에 대하여 공소시효를 정지시키는 법률이라 하더라도 그 사유만으로 헌법 제12조 제1항 및 제 13조 제1항에 규정한 죄형법정주의의 파생원칙인 형벌불소급의 원칙에 언제나 위배되는 것으로 단 정할 수는 없다. 4. 공소시효가 아직 완성되지 않은 경우 위 법률조항은 단지 진행중인 공소시효를 연장하는 법 률로서 이른바 부진정소급효를 갖게 되나, 공소시효제도에 근거한 개인의 신뢰와 공시시효의 연장 을 통하여 달성하려는 공익을 비교형량하여 공익이 개인의 신뢰보호이익에 우선하는 경우에는 소 급효를 갖는 법률도 헌법상 정당화될 수 있다. <합헌의견> 가.','행위의 가벌성','형법 표준판례 5. 진정ㆍ부진정 소급효 헌법재판소 1996. 2. 16. 선고 96헌가2 전원재판부','','판례검색'),
(18,'형법 표준판례 5. 진정ㆍ부진정 소급효 헌법재판소 1996. 2. 16. 선고 96헌가2 전원재판부','3. 형벌불소급의 원칙은 “행위의 가벌성” 즉 형사소추가 “언제부터 어떠한 조건하에서” 가능한가 의 문제에 관한 것이고, “(A)” 가능한가의 문제에 관한 것은 아니므로, 과거에 이미 행한 범 죄에 대하여 공소시효를 정지시키는 법률이라 하더라도 그 사유만으로 헌법 제12조 제1항 및 제 13조 제1항에 규정한 죄형법정주의의 파생원칙인 형벌불소급의 원칙에 언제나 위배되는 것으로 단 정할 수는 없다. 4. 공소시효가 아직 완성되지 않은 경우 위 법률조항은 단지 진행중인 공소시효를 연장하는 법 률로서 이른바 부진정소급효를 갖게 되나, 공소시효제도에 근거한 개인의 신뢰와 공시시효의 연장 을 통하여 달성하려는 공익을 비교형량하여 공익이 개인의 신뢰보호이익에 우선하는 경우에는 소 급효를 갖는 법률도 헌법상 정당화될 수 있다. <합헌의견> 가.','얼마동안','형법 표준판례 5. 진정ㆍ부진정 소급효 헌법재판소 1996. 2. 16. 선고 96헌가2 전원재판부','','판례검색'),
(19,'민법 표준판례 7. 신의성실의 원칙：강행법규 위반과의 관계 대법원 2013. 12. 18. 선고 2012다89399 전원합의체 판결','단체협약 등 노사합의의 내용이 근로기준법의 강행규정을 위반하여 무효인 경우에, 무효를 주장 하는 것이 신의칙에 위배되는 권리의 행사라는 이유로 이를 배척한다면 강행규정으로 정한 입법 취지를 몰각시키는 결과가 될 것이므로, 그러한 주장이 신의칙에 위배된다고 볼 수 없음이 원칙이 다. 그러나 노사합의의 내용이 근로기준법의 강행규정을 위반한다고 하여 노사합의의 (A) 주장에 대하여 예외 없이 신의칙의 적용이 배제되는 것은 아니다. 신의칙을 적용하기 위한 일반적인 요건 을 갖춤은 물론 근로기준법의 강행규정성에도 불구하고 신의칙을 우선하여 적용하는 것을 수긍할 만한 특별한 사정이 있는 예외적인 경우에 한하여 노사합의의 무효를 주장하는 것은 신의칙에 위 배되어 허용될 수 없다.','무효','민법 표준판례 7. 신의성실의 원칙：강행법규 위반과의 관계 대법원 2013. 12. 18. 선고 2012다89399 전원합의체 판결','','판례검색'),
(20,'민법 표준판례 8. 신의성실의 원칙：실효의 원칙 대법원 1990. 8. 28. 선고 90다카9619 판결','권리행사가 이른바 신의칙에 반하는 결과가 되어 허용되지 않는 경우라는 것은 권리자의 주관적 인 동기가 고려되지 않는다 하더라도 그에게 권리행사의 기회가 있어서 이를 현실적으로 기대할 수가 있었음에도 불구하고 행사하지 않은 경우에 한하는 것인바, 조건부 징계해임처분을 당한 원고 가 퇴직금을 수령하였다 하여 위 조건부 징계해임결의절차에 하자가 있어서 그 결의 자체가 (A) 라는 것까지 알면서 이를 승인한 것으로 단정하기는 어렵고, 또한 그 후 원고와 같이 조건부 징계 해임결의에 따라 사직원을 제출하여 의원면직으로 처리된 사람이 피고를 상대로 제기한 소송이 대 법원의 상고기각판결로 피고패소가 확정되자 곧바로 원고가 이 사건 소를 제기한 것이 징계처분일 로부터 10년 남짓 기간이 경과된 후인 경우에는 원고의 권리행사의 지체가 그의 단순한 주관적인 동기에 비롯된 것으로 보기 어렵고 상대방인 피고로서도 이제는 원고가 그의 권리를 행사하지 아 니할 것이라고 신뢰할 정당한 사유가 있었다고 볼 수 없으니, 원고의 권리행사가 신의성실에 반하 여 그 권리가 실효되었다고 단정할 수는 없다.','무효','민법 표준판례 8. 신의성실의 원칙：실효의 원칙 대법원 1990. 8. 28. 선고 90다카9619 판결','','판례검색'),
(21,'헌법 표준판례 7. 방어적 민주주의와 정당해산제도','따 라서 모든 정당의 존립과 활동은 최대한 보장되며, 설령 어떤 정당이 민주적 기본질서를 부정하고 이를 적극적으로 공격하는 것으로 보인다 하더라도 국민의 정치적 의사형성에 참여하는 정당으로 서 존재하는 한 헌법에 의해 최대한 두텁게 보호되므로, 단순히 행정부의 통상적인 처분에 의해서 는 해산될 수 없고, 오직 헌법재판소가 그 정당의 위헌성을 확인하고 해산의 필요성을 인정한 경 우에만 정당정치의 영역에서 배제된다. 그러나 한편 이 제도로 인해서, 정당활동의 자유가 인정된 다 하더라도 민주적 기본질서를 침해해서는 안 된다는 헌법적 한계 역시 설정된다. 2. 가. ‘(A)’이란, 어떤 정당이 추구하는 정치적 방향이나 지향점 혹은 현실 속에서 구 현하고자 하는 정치적 계획 등을 통칭한다.','정당의 목적','헌법 표준판례 7. 방어적 민주주의와 정당해산제도','','판례검색'),
(22,'헌법 표준판례 7. 방어적 민주주의와 정당해산제도','가. ‘(A)’이란, 어떤 정당이 추구하는 정치적 방향이나 지향점 혹은 현실 속에서 구 현하고자 하는 정치적 계획 등을 통칭한다. 이는 주로 정당의 공식적인 강령이나 당헌의 내용을 통해 드러나겠지만, 그밖에 정당대표나 주요 당직자 등의 공식적 발언, 정당의 기관지나 선전자료 와 같은 간행물, 정당의 의사결정과정에서 일정한 영향력을 가지거나 정당의 이념으로부터 영향을 받은 당원들의 행위 등도 정당의 목적을 파악하는 데에 도움이 될 수 있다. 만약 정당의 진정한 목적이 숨겨진 상태라면 이 경우에는 강령 이외의 자료를 통해 진정한 목적을 파악해야 한다. 한편 ‘정당의 활동’이란, 정당 기관의 행위나 주요 정당관계자, 당원 등의 행위로서 그 정당에게 귀속시킬 수 있는 활동 일반을 의미한다.','정당의 목적','헌법 표준판례 7. 방어적 민주주의와 정당해산제도','','판례검색'),
(23,'헌법 표준판례 7. 방어적 민주주의와 정당해산제도','가. ‘정당의 목적’이란, 어떤 정당이 추구하는 정치적 방향이나 지향점 혹은 현실 속에서 구 현하고자 하는 정치적 계획 등을 통칭한다. 이는 주로 정당의 공식적인 강령이나 당헌의 내용을 통해 드러나겠지만, 그밖에 정당대표나 주요 당직자 등의 공식적 발언, 정당의 기관지나 선전자료 와 같은 간행물, 정당의 의사결정과정에서 일정한 영향력을 가지거나 정당의 이념으로부터 영향을 받은 당원들의 행위 등도 정당의 목적을 파악하는 데에 도움이 될 수 있다. 만약 정당의 진정한 목적이 숨겨진 상태라면 이 경우에는 강령 이외의 자료를 통해 진정한 목적을 파악해야 한다. 한편 ‘(A)’이란, 정당 기관의 행위나 주요 정당관계자, 당원 등의 행위로서 그 정당에게 귀속시킬 수 있는 활동 일반을 의미한다.','정당의 활동','헌법 표준판례 7. 방어적 민주주의와 정당해산제도','','판례검색'),
(24,'민법 표준판례 10. 신의성실의 원칙： 보호의무 대법원 2000. 11. 24. 선고 2000다38718, 38725 판결','공중접객업인 숙박업을 경영하는 자가 투숙객과 체결하는 숙박계약은 숙박업자가 고객에게 숙박 을 할 수 있는 객실을 제공하여 고객으로 하여금 이를 사용할 수 있도록 하고 고객으로부터 그 대 가를 받는 일종의 일시 사용을 위한 임대차계약으로서 객실 및 관련 시설은 오로지 숙박업자의 지 배 아래 놓여 있는 것이므로 숙박업자는 통상의 임대차와 같이 단순히 여관 등의 객실 및 관련 시 설을 제공하여 고객으로 하여금 이를 사용·수익하게 할 의무를 부담하는 것에서 한 걸음 더 나아 가 고객에게 위험이 없는 안전하고 편안한 객실 및 관련 시설을 제공함으로써 고객의 안전을 배려 하여야 할 보호의무를 부담하며 이러한 의무는 숙박계약의 특수성을 고려하여 신의칙상 인정되는 부수적인 의무로서 숙박업자가 이를 위반하여 고객의 생명·신체를 침해하여 투숙객에게 손해를 입 힌 경우 불완전이행으로 인한 채무불이행책임을 부담하고, 이 경우 (A) 의 존재와 그 위반 사실을 주장·입증하여야 하며 숙박업자로서는 통상의 채무불이행에 있어서와 마찬가지로 그 채무불이행에 관하여 자기에게 과실이 없음을 주장·입증하지 못하는 한 그 책임을 면할 수는 없다.','피해자로서는 구체적 보호의무','민법 표준판례 10. 신의성실의 원칙： 보호의무 대법원 2000. 11. 24. 선고 2000다38718, 38725 판결','','판례검색'),
(25,'민법 표준판례 11. 신의성실의 원칙：금반언의 원칙 대법원 1994. 9. 27. 선고 94다20617 판결','갑이 대리권 없이 을 소유 부동산을 병에게 매도하여 부동산소유권이전등기등에관한특별조치법 에 의하여 소유권이전등기를 마쳐주었다면 그 매매계약은 무효이고 이에 터잡은 이전등기 역시 무 효가 되나, 갑은 을의 무권대리인으로서 제135조 제1항의 규정에 의하여 매수인인 병에게 부동산 에 대한 소유권이전등기를 이행할 의무가 있으므로 그러한 지위에 있는 갑이 을로부터 부동산을 상속받아 그 소유자가 되어 소유권이전등기이행의무를 이행하는 것이 가능하게 된 시점에서 자신 이 소유자라고 하여 자신으로부터 부동산을 전전매수한 정에게 원래 자신의 매매행위가 (A) 행위여서 무효였다는 이유로 정 앞으로 경료된 소유권이전등기가 무효의 등기라고 주장하여 그 등 기의 말소를 청구하거나 부동산의 점유로 인한 부당이득금의 반환을 구하는 것은 금반언의 원칙이 나 신의성실의 원칙에 반하여 허용될 수 없다.','무권대리','민법 표준판례 11. 신의성실의 원칙：금반언의 원칙 대법원 1994. 9. 27. 선고 94다20617 판결','','판례검색'),
(26,'민법 표준판례 11. 신의성실의 원칙：금반언의 원칙 대법원 1994. 9. 27. 선고 94다20617 판결','갑이 (A) 없이 을 소유 부동산을 병에게 매도하여 부동산소유권이전등기등에관한특별조치법 에 의하여 소유권이전등기를 마쳐주었다면 그 매매계약은 무효이고 이에 터잡은 이전등기 역시 무 효가 되나, 갑은 을의 무권대리인으로서 제135조 제1항의 규정에 의하여 매수인인 병에게 부동산 에 대한 소유권이전등기를 이행할 의무가 있으므로 그러한 지위에 있는 갑이 을로부터 부동산을 상속받아 그 소유자가 되어 소유권이전등기이행의무를 이행하는 것이 가능하게 된 시점에서 자신 이 소유자라고 하여 자신으로부터 부동산을 전전매수한 정에게 원래 자신의 매매행위가 무권대리 행위여서 무효였다는 이유로 정 앞으로 경료된 소유권이전등기가 무효의 등기라고 주장하여 그 등 기의 말소를 청구하거나 부동산의 점유로 인한 부당이득금의 반환을 구하는 것은 금반언의 원칙이 나 신의성실의 원칙에 반하여 허용될 수 없다.','대리권','민법 표준판례 11. 신의성실의 원칙：금반언의 원칙 대법원 1994. 9. 27. 선고 94다20617 판결','','판례검색'),
(27,'민법 표준판례 12. 신의성실의 원칙： 호의동승 대법원 1999. 2. 9. 선고 98다53141 판결','차량의 운행자가 아무런 대가를 받지 아니하고 동승자의 편의와 이익을 위하여 동승을 허락하고 동승자도 그 자신의 편의와 이익을 위하여 그 제공을 받은 경우 그 운행 목적, (A), 그가 차에 동승한 경위, 특히 동승을 요구한 목적과 적극성 등 여러 사정에 비추어 가해 자에게 일반 교통사고와 동일한 책임을 지우는 것이 신의법칙이나 형평의 원칙으로 보아 매우 불 합리하다고 인정될 때에는 그 배상액을 경감할 수 있으나, 사고 차량에 단순히 호의로 동승 하였다 는 사실만 가지고 바로 이를 배상액 경감사유로 삼을 수 있는 것은 아니다.','동승자와 운행자의 인적관계','민법 표준판례 12. 신의성실의 원칙： 호의동승 대법원 1999. 2. 9. 선고 98다53141 판결','','판례검색'),
(28,'형법 표준판례 7. 책임주의 헌법재판소 2007. 11. 29. 선고 2005헌가10 전원재판부','이 사건 법률조항이 종업원의 업무 관련 무면허의료행위가 있으면 이에 대해 영업주가 비난받을 만한 행위가 있었는지 여부와는 관계없이 자동적으로 영업주도 처벌하도록 규정하고 있고, 그 문언 상 명백한 의미와 달리 “종업원의 범죄행위에 대해 영업주의 선임감독상의 (A)(기타 영업주의 귀 책사유)이 인정되는 경우”라는 요건을 추가하여 해석하는 것은 문리해석의 범위를 넘어서는 것으로 서 허용될 수 없으므로, 결국 위 법률조항은 다른 사람의 범죄에 대해 그 책임 유무를 묻지 않고 형벌을 부과함으로써, 법정형에 나아가 판단할 것 없이, 형사법의 기본원리인 ‘책임없는 자에게 형 벌 을 부 과 할 수 없 다 ’ 는 책 임 주 의 에 반 한 다.','과실','형법 표준판례 7. 책임주의 헌법재판소 2007. 11. 29. 선고 2005헌가10 전원재판부','','판례검색'),
(29,'형법 표준판례 7. 책임주의 헌법재판소 2007. 11. 29. 선고 2005헌가10 전원재판부','이 사건 법률조항이 종업원의 업무 관련 무면허의료행위가 있으면 이에 대해 영업주가 비난받을 만한 행위가 있었는지 여부와는 관계없이 자동적으로 영업주도 처벌하도록 규정하고 있고, 그 문언 상 명백한 의미와 달리 “종업원의 범죄행위에 대해 영업주의 선임감독상의 과실(기타 (A))이 인정되는 경우”라는 요건을 추가하여 해석하는 것은 문리해석의 범위를 넘어서는 것으로 서 허용될 수 없으므로, 결국 위 법률조항은 다른 사람의 범죄에 대해 그 책임 유무를 묻지 않고 형벌을 부과함으로써, 법정형에 나아가 판단할 것 없이, 형사법의 기본원리인 ‘책임없는 자에게 형 벌 을 부 과 할 수 없 다 ’ 는 책 임 주 의 에 반 한 다.','영업주의 귀 책사유','형법 표준판례 7. 책임주의 헌법재판소 2007. 11. 29. 선고 2005헌가10 전원재판부','','판례검색'),
(30,'헌법 표준판례 9. 선거운동 개념 및 사전선거운동금지','1. 선거운동이라 함은 특정 후보자의 당선 내지 이를 위한 득표에 필요한 모든 행위 또는 특정 후보자의 낙선에 필요한 모든 행위 중 당선 또는 낙선을 위한 것이라는 목적의사가 객관적으로 인 정될 수 있는 능동적, 계획적 행위를 말하는 것으로 풀이할 수 있다. 즉, 단순한 의견개진 등과 구 별되는 가벌적 행위로서의 선거운동의 표지로 당선 내지 득표(반대후보자의 낙선)에의 목적성, 그 목적성의 객관적 인식가능성, 능동성 및 계획성이 요구된다 할 것이다. ‘(A)’을 위와 같이 풀이한다면 법집행자의 자의를 허용할 소지를 제거할 수 있고, 건전한 상식과 통상적인 법감정을 가진 사람이면 누구나 그러한 표지를 갖춘 선거운동과 단순한 의견개진 을 구분할 수 있으므로 헌법 제12조 제1항이 요구하는 죄형법정주의의 명확성의 원칙에 위배된다 고 할 수 없다. 2.','선거운동','헌법 표준판례 9. 선거운동 개념 및 사전선거운동금지','','판례검색'),
(31,'헌법 표준판례 9. 선거운동 개념 및 사전선거운동금지','‘(A)’을 위와 같이 풀이한다면 법집행자의 자의를 허용할 소지를 제거할 수 있고, 건전한 상식과 통상적인 법감정을 가진 사람이면 누구나 그러한 표지를 갖춘 선거운동과 단순한 의견개진 을 구분할 수 있으므로 헌법 제12조 제1항이 요구하는 죄형법정주의의 명확성의 원칙에 위배된다 고 할 수 없다. 2. 기간의 제한 없이 선거운동을 무한정 허용할 경우에는 후보자간의 지나친 경쟁이 선거관리의 곤란으로 이어져 부정행위의 발생을 막기 어렵게 된다. 또한 후보자간의 무리한 경쟁의 장기화는 경비와 노력이 지나치게 들어 사회경제적으로 많은 손실을 가져올 뿐만 아니라 후보자간의 경제력 차이에 따른 불공평이 생기게 되고 아울러 막대한 선거비용을 마련할 수 없는 젊고 유능한 신참 후보자의 입후보의 기회를 빼앗는 결과를 가져올 수 있다. 선거운동의 기간제한은 제한의 입법목 적, 제한의 내용, 우리나라에서의 선거의 태양, 현실적 필요성 등을 고려할 때 필요하고도 합리적 인 제한이며, 선거운동의 자유를 형해화할 정도로 과도하게 제한하는 것으로 볼 수 없다.','선거운동','헌법 표준판례 9. 선거운동 개념 및 사전선거운동금지','','판례검색'),
(32,'민법 표준판례 15. 권리남용금지의 원칙 대법원 1992. 6. 12. 선고 92다12384, 92다912391 판결','매매계약 체결 후 부동산의 시가가 등귀하였고, 매수인이 잔대금 지급기일을 경과한 지금까지 매매대금 중 7분의 6에 해당하는 금원을 지급하지 (A) 후 19년이 지난 후에 소유 권이전등기청구의 소를 제기하였다 하더라도 이러한 사유만으로 그 청구가 신의칙에 반하고 권리 남용에 해당한다고 볼 수 없다.','아니한 채 매매계약','민법 표준판례 15. 권리남용금지의 원칙 대법원 1992. 6. 12. 선고 92다12384, 92다912391 판결','','판례검색'),
(33,'민법 표준판례 15. 권리남용금지의 원칙 대법원 1992. 6. 12. 선고 92다12384, 92다912391 판결','(A) 체결 후 부동산의 시가가 등귀하였고, 매수인이 잔대금 지급기일을 경과한 지금까지 매매대금 중 7분의 6에 해당하는 금원을 지급하지 아니한 채 매매계약 후 19년이 지난 후에 소유 권이전등기청구의 소를 제기하였다 하더라도 이러한 사유만으로 그 청구가 신의칙에 반하고 권리 남용에 해당한다고 볼 수 없다.','매매계약','민법 표준판례 15. 권리남용금지의 원칙 대법원 1992. 6. 12. 선고 92다12384, 92다912391 판결','','판례검색'),
(34,'민법 표준판례 15. 권리남용금지의 원칙 대법원 1992. 6. 12. 선고 92다12384, 92다912391 판결','매매계약 체결 후 부동산의 시가가 등귀하였고, 매수인이 잔대금 지급기일을 경과한 지금까지 매매대금 중 7분의 6에 해당하는 금원을 지급하지 아니한 채 (A) 후 19년이 지난 후에 소유 권이전등기청구의 소를 제기하였다 하더라도 이러한 사유만으로 그 청구가 신의칙에 반하고 권리 남용에 해당한다고 볼 수 없다.','매매계약','민법 표준판례 15. 권리남용금지의 원칙 대법원 1992. 6. 12. 선고 92다12384, 92다912391 판결','','판례검색'),
(35,'민법 표준판례 16. 태아의 권리능력 대법원 1982. 2. 9. 선고 81다534 판결','의용 민법이나 구관습하에 태아에게는 일반적으로 권리능력이 인정되지 아니하고 손해배상청구 권 또는 (A) 등 특별한 경우에 한하여 제한된 권리능력을 인정하였을 따름이므로 증여에 관하여 는 태아의 수증능력이 인정되지 아니하였고, 또 태아인 동안에는 법정대리인이 있을 수 없으므로 법정대리인에 의한 수증행위도 할 수 없다.','상속','민법 표준판례 16. 태아의 권리능력 대법원 1982. 2. 9. 선고 81다534 판결','','판례검색'),
(36,'민법 표준판례 19. 미성년자의 행위능력 대법원 2007. 11. 16. 선고 2005다 71659, 71666, 71673 판결','행위무능력자 제도는 사적자치의 원칙이라는 민법의 기본이념, 특히, (A) 원칙의 구현을 가 능케 하는 도구로서 인정되는 것이고, 거래의 안전을 희생시키더라도 행위무능력자를 보호하고자 함에 근본적인 입법 취지가 있는바, 행위무능력자 제도의 이러한 성격과 입법 취지 등에 비추어 볼 때, 신용카드 가맹점이 미성년자와 신용구매계약을 체결할 당시 향후 그 미성년자가 법정대리인 의 동의가 없었음을 들어 스스로 위 계약을 취소하지는 않으리라고 신뢰하였다 하더라도 그 신뢰 가 객관적으로 정당한 것이라고 할 수 있을지 의문일 뿐만 아니라, 그 미성년자가 가맹점의 이러 한 신뢰에 반하여 취소권을 행사하는 것이 정의관념에 비추어 용인될 수 없는 정도의 상태라고 보 기도 어려우며, 미성년자의 법률행위에 법정대리인의 동의를 요하도록 하는 것은 강행규정인데, 위 규정에 반하여 이루어진 신용구매계약을 미성년자 스스로 취소하는 것을 신의칙 위반을 이유로 배 척한다면, 이는 오히려 위 규정에 의해 배제하려는 결과를 실현시키는 셈이 되어 미성년자 제도의 입법 취지를 몰각시킬 우려가 있으므로, 법정대리인의 동의 없이 신용구매계약을 체결한 미성년자 가 사후에 법정대리인의 동의 없음을 사유로 들어 이를 취소하는 것이 신의칙에 위배된 것이라고 할 수 없다.','자기책임','민법 표준판례 19. 미성년자의 행위능력 대법원 2007. 11. 16. 선고 2005다 71659, 71666, 71673 판결','','판례검색'),
(37,'헌법 표준판례 11. 비례대표의석배분방식으로서 1인 1표제의 위헌성','가. 공직선거및선거부정방 지법(이하 “(A)”)은 이른바 1인 1표제를 채택하여(제146조 제2항 ) 유권자에게 별도의 정당투표를 인정하지 않고 있으며, 지역구선거에서 표출된 유권자의 의사를 그 대로 정당에 대한 지지의사로 의제 하여 비례대표의석을 배분토록 하고 있는바(제189조 제1항), 이 러한 비례대표제 방식에 의하면, 유권자가 지역구후보자나 그가 속한 정당 중 어느 일방만을 지지 할 경우 지역구후보자 개인을 기준으로 투표하든, 정당을 기준으로 투표하든 어느 경우에나 자신의 진정한 의사는 반영시킬 수 없으며, 후보자든 정당이든 절반의 선택권을 박탈당할 수밖에 없을 뿐 만 아니라, 신생정당에 대한 국민의 지지도를 제대로 반영할 수 없어 기존의 세력정당에 대한 국 민의 실제 지지도를 초과하여 그 세력정당에 의석을 배분하여 주게 되는바, 이는 선거에 있어 국 민의 의사를 제대로 반영하고, 국민의 자유로운 선택권을 보장할 것 등을 요구하는 민주주의원리에 부합하지 않는다. 나. 비례대표제를 채택하는 경우 직접선거의 원칙은 의원의 선출뿐만 아니라 정당의 비례적인 의석확보도 선거권자의 투표에 의하여 직접 결정될 것을 요구하는바, 비례대표의원의 선거는 지역 구의원의 선거와는 별도의 선거이므로 이에 관한 유권자의 별도의 의사표시, 즉 정당명부에 대한 별도의 투표가 있어야 함에도 현행제도는 정당명부에 대한 투표가 따로 없으므로 결국 비례대표의 원의 선출에 있어서는 정당의 명부작성행위가 최종적·결정적인 의의를 지니게 되고, 선거권자들의 투표행위로써 비례대표의원의 선출을 직접·결정적으로 좌우할 수 없으므로 직접선거의 원칙에 위 배된다. 다.','공선법','헌법 표준판례 11. 비례대표의석배분방식으로서 1인 1표제의 위헌성','','판례검색'),
(38,'헌법 표준판례 12. 언론인의 선거운동금지','1. 금지조항은 ‘(A)’이라고만 하여 ‘언론인’이라는 단어 외에 대통령령에 서 정할 내용의 한계를 설정하지 않았다. 관련조항들을 종합하여 보아도 방송, 신문, 뉴스통신 등 과 같이 다양한 언론매체 중에서 어느 범위로 한정될지, 어떤 업무에 어느 정도 관여하는 자까지 언론인에 포함될 것인지 등을 예측하기 어렵다. 그러므로 금지조항은 포괄위임금지원칙을 위반 한다. 2.','대통령령으로 정하는 언론인','헌법 표준판례 12. 언론인의 선거운동금지','','판례검색'),
(39,'헌법 표준판례 12. 언론인의 선거운동금지','1. 금지조항은 ‘대통령령으로 정하는 (A)’이라고만 하여 ‘언론인’이라는 단어 외에 대통령령에 서 정할 내용의 한계를 설정하지 않았다. 관련조항들을 종합하여 보아도 방송, 신문, 뉴스통신 등 과 같이 다양한 언론매체 중에서 어느 범위로 한정될지, 어떤 업무에 어느 정도 관여하는 자까지 언론인에 포함될 것인지 등을 예측하기 어렵다. 그러므로 금지조항은 포괄위임금지원칙을 위반 한다. 2.','언론인','헌법 표준판례 12. 언론인의 선거운동금지','','판례검색'),
(40,'헌법 표준판례 12. 언론인의 선거운동금지','1. 금지조항은 ‘대통령령으로 정하는 언론인’이라고만 하여 ‘(A)’이라는 단어 외에 대통령령에 서 정할 내용의 한계를 설정하지 않았다. 관련조항들을 종합하여 보아도 방송, 신문, 뉴스통신 등 과 같이 다양한 언론매체 중에서 어느 범위로 한정될지, 어떤 업무에 어느 정도 관여하는 자까지 언론인에 포함될 것인지 등을 예측하기 어렵다. 그러므로 금지조항은 포괄위임금지원칙을 위반 한다. 2.','언론인','헌법 표준판례 12. 언론인의 선거운동금지','','판례검색'),
(41,'형법 표준판례 14. 대표자의 위법과 법인의 처벌','법인은 기관을 통하여 행위하므로 법인이 대표자를 선임한 이상 그의 행위로 인한 법률효과는 법인에게 귀속되어야 하고, 법인 대표자의 범죄행위에 대하여는 법인 자신이 자신의 행위에 대한 책임을 부담하여야 하는바, 법인 대표자의 법규위반행위에 대한 법인의 책임은 법인 자신의 법규위 반행위로 평가될 수 있는 행위에 대한 법인의 직접책임으로서, 대표자의 고의에 의한 위반행위에 대하여는 법인 자신의 고의에 의한 책임을, 대표자의 과실에 의한 위반행위에 대하여는 법인 자신 의 과실에 의한 책임을 부담하는 것이다. 따라서, 법인의 ‘(A)’ 관련 부분은 대표자의 책임을 요건으로 하여 법인을 처벌하므로 책임주의원칙에 반하지 아니한다.','대표자','형법 표준판례 14. 대표자의 위법과 법인의 처벌','','판례검색'),
(42,'형법 표준판례 15. 즉시범 대법원 2009. 4. 16. 선고 2007도6703 전원합의체 판결','[다수의견] 구 농지법(2005. 1. 14. 법률 제7335호로 개정되기 전의 것) 제2조 제9호에서 말하 는 ‘농지의 전용’이 이루어지는 태양은, 첫째로 농지에 대하여 절토, 성토 또는 정지를 하거나 농 지로서의 사용에 장해가 되는 유형물을 설치하는 등으로 농지의 형질을 외형상으로뿐만 아니라 사 실상 변경시켜 원상회복이 어려운 상태로 만드는 경우가 있고, 둘째로 농지에 대하여 외부적 형상 의 변경을 수반하지 않거나 외부적 형상의 변경을 수반하더라도 사회통념상 원상회복이 어려운 정 형법 총론 제 2 편 범 죄 론 도에 이르지 않은 상태에서 그 농지를 다른 목적에 사용하는 경우 등이 있을 수 있다. 전자의 경 (A) 자체에 의하여 당해 토지가 농지로서의 기능을 상실하여 그 이후 그 토지 를 농업생산 등 외의 목적으로 사용하는 행위가 더 이상 ‘농지의 전용’에 해당하지 않는다고 할 때 에는, 허가 없이 그와 같이 농지를 전용한 죄는 그와 같은 행위가 종료됨으로써 즉시 성립하고 그 와 동시에 완성되는 즉시범이라고 보아야 한다.','우와 같이 농지전용행위','형법 표준판례 15. 즉시범 대법원 2009. 4. 16. 선고 2007도6703 전원합의체 판결','','판례검색'),
(43,'형법 표준판례 15. 즉시범 대법원 2009. 4. 16. 선고 2007도6703 전원합의체 판결','[다수의견] 구 농지법(2005. 1. 14. 법률 제7335호로 개정되기 전의 것) 제2조 제9호에서 말하 는 ‘(A)’이 이루어지는 태양은, 첫째로 농지에 대하여 절토, 성토 또는 정지를 하거나 농 지로서의 사용에 장해가 되는 유형물을 설치하는 등으로 농지의 형질을 외형상으로뿐만 아니라 사 실상 변경시켜 원상회복이 어려운 상태로 만드는 경우가 있고, 둘째로 농지에 대하여 외부적 형상 의 변경을 수반하지 않거나 외부적 형상의 변경을 수반하더라도 사회통념상 원상회복이 어려운 정 형법 총론 제 2 편 범 죄 론 도에 이르지 않은 상태에서 그 농지를 다른 목적에 사용하는 경우 등이 있을 수 있다. 전자의 경 우와 같이 농지전용행위 자체에 의하여 당해 토지가 농지로서의 기능을 상실하여 그 이후 그 토지 를 농업생산 등 외의 목적으로 사용하는 행위가 더 이상 ‘농지의 전용’에 해당하지 않는다고 할 때 에는, 허가 없이 그와 같이 농지를 전용한 죄는 그와 같은 행위가 종료됨으로써 즉시 성립하고 그 와 동시에 완성되는 즉시범이라고 보아야 한다.','농지의 전용','형법 표준판례 15. 즉시범 대법원 2009. 4. 16. 선고 2007도6703 전원합의체 판결','','판례검색'),
(44,'형법 표준판례 15. 즉시범 대법원 2009. 4. 16. 선고 2007도6703 전원합의체 판결','[다수의견] 구 농지법(2005. 1. 14. 법률 제7335호로 개정되기 전의 것) 제2조 제9호에서 말하 는 ‘농지의 전용’이 이루어지는 태양은, 첫째로 농지에 대하여 절토, 성토 또는 정지를 하거나 농 지로서의 사용에 장해가 되는 유형물을 설치하는 등으로 농지의 형질을 외형상으로뿐만 아니라 사 실상 변경시켜 원상회복이 어려운 상태로 만드는 경우가 있고, 둘째로 농지에 대하여 외부적 형상 의 변경을 수반하지 않거나 외부적 형상의 변경을 수반하더라도 사회통념상 원상회복이 어려운 정 형법 총론 제 2 편 범 죄 론 도에 이르지 않은 상태에서 그 농지를 다른 목적에 사용하는 경우 등이 있을 수 있다. 전자의 경 우와 같이 농지전용행위 자체에 의하여 당해 토지가 농지로서의 기능을 상실하여 그 이후 그 토지 를 농업생산 등 외의 목적으로 사용하는 행위가 더 이상 ‘(A)’에 해당하지 않는다고 할 때 에는, 허가 없이 그와 같이 농지를 전용한 죄는 그와 같은 행위가 종료됨으로써 즉시 성립하고 그 와 동시에 완성되는 즉시범이라고 보아야 한다.','농지의 전용','형법 표준판례 15. 즉시범 대법원 2009. 4. 16. 선고 2007도6703 전원합의체 판결','','판례검색'),
(45,'형법 표준판례 15. 즉시범 대법원 2009. 4. 16. 선고 2007도6703 전원합의체 판결','법률 제7335호로 개정되기 전의 것) 제2조 제9호에서 말하 는 ‘농지의 전용’이 이루어지는 태양은, 첫째로 농지에 대하여 절토, 성토 또는 정지를 하거나 농 지로서의 사용에 장해가 되는 유형물을 설치하는 등으로 농지의 형질을 외형상으로뿐만 아니라 사 실상 변경시켜 원상회복이 어려운 상태로 만드는 경우가 있고, 둘째로 농지에 대하여 외부적 형상 의 변경을 수반하지 않거나 외부적 형상의 변경을 수반하더라도 사회통념상 원상회복이 어려운 정 형법 총론 제 2 편 범 죄 론 도에 이르지 않은 상태에서 그 농지를 다른 목적에 사용하는 경우 등이 있을 수 있다. 전자의 경 (A) 자체에 의하여 당해 토지가 농지로서의 기능을 상실하여 그 이후 그 토지 를 농업생산 등 외의 목적으로 사용하는 행위가 더 이상 ‘농지의 전용’에 해당하지 않는다고 할 때 에는, 허가 없이 그와 같이 농지를 전용한 죄는 그와 같은 행위가 종료됨으로써 즉시 성립하고 그 와 동시에 완성되는 즉시범이라고 보아야 한다. 그러나 후자의 경우와 같이 당해 토지를 농업생산 등 외의 다른 목적으로 사용하는 행위를 여전히 농지전용으로 볼 수 있는 때에는 허가 없이 그와 같이 농지를 전용하는 죄는 계속범으로서 그 토지를 다른 용도로 사용하는 한 가벌적인 위법행위 가 계속 반복되고 있는 계속범이라고 보아야 한다. → 농지에 잡석 등을 깔아 정지작업이 이루어져 사실상 원상회복이 어렵게 된 토지를 전용하였 다는 공소사실에 대하여, 공소 범행 당시 농지로서의 현상을 상실한 토지를 사용한 것이 농지전용 죄를 구성하는지 여부를 먼저 살펴본 다음 공소시효의 기산점을 판단하여야 한다는 이유로, 정지작업 의 종료시점을 공소시효의 기산점으로 보아 공소시효가 완성되었다고 본 원심판결을 파기한 사례.','우와 같이 농지전용행위','형법 표준판례 15. 즉시범 대법원 2009. 4. 16. 선고 2007도6703 전원합의체 판결','','판례검색'),
(46,'형법 표준판례 15. 즉시범 대법원 2009. 4. 16. 선고 2007도6703 전원합의체 판결','법률 제7335호로 개정되기 전의 것) 제2조 제9호에서 말하 는 ‘(A)’이 이루어지는 태양은, 첫째로 농지에 대하여 절토, 성토 또는 정지를 하거나 농 지로서의 사용에 장해가 되는 유형물을 설치하는 등으로 농지의 형질을 외형상으로뿐만 아니라 사 실상 변경시켜 원상회복이 어려운 상태로 만드는 경우가 있고, 둘째로 농지에 대하여 외부적 형상 의 변경을 수반하지 않거나 외부적 형상의 변경을 수반하더라도 사회통념상 원상회복이 어려운 정 형법 총론 제 2 편 범 죄 론 도에 이르지 않은 상태에서 그 농지를 다른 목적에 사용하는 경우 등이 있을 수 있다. 전자의 경 우와 같이 농지전용행위 자체에 의하여 당해 토지가 농지로서의 기능을 상실하여 그 이후 그 토지 를 농업생산 등 외의 목적으로 사용하는 행위가 더 이상 ‘농지의 전용’에 해당하지 않는다고 할 때 에는, 허가 없이 그와 같이 농지를 전용한 죄는 그와 같은 행위가 종료됨으로써 즉시 성립하고 그 와 동시에 완성되는 즉시범이라고 보아야 한다. 그러나 후자의 경우와 같이 당해 토지를 농업생산 등 외의 다른 목적으로 사용하는 행위를 여전히 농지전용으로 볼 수 있는 때에는 허가 없이 그와 같이 농지를 전용하는 죄는 계속범으로서 그 토지를 다른 용도로 사용하는 한 가벌적인 위법행위 가 계속 반복되고 있는 계속범이라고 보아야 한다. → 농지에 잡석 등을 깔아 정지작업이 이루어져 사실상 원상회복이 어렵게 된 토지를 전용하였 다는 공소사실에 대하여, 공소 범행 당시 농지로서의 현상을 상실한 토지를 사용한 것이 농지전용 죄를 구성하는지 여부를 먼저 살펴본 다음 공소시효의 기산점을 판단하여야 한다는 이유로, 정지작업 의 종료시점을 공소시효의 기산점으로 보아 공소시효가 완성되었다고 본 원심판결을 파기한 사례.','농지의 전용','형법 표준판례 15. 즉시범 대법원 2009. 4. 16. 선고 2007도6703 전원합의체 판결','','판례검색'),
(47,'형법 표준판례 15. 즉시범 대법원 2009. 4. 16. 선고 2007도6703 전원합의체 판결','법률 제7335호로 개정되기 전의 것) 제2조 제9호에서 말하 는 ‘농지의 전용’이 이루어지는 태양은, 첫째로 농지에 대하여 절토, 성토 또는 정지를 하거나 농 지로서의 사용에 장해가 되는 유형물을 설치하는 등으로 농지의 형질을 외형상으로뿐만 아니라 사 실상 변경시켜 원상회복이 어려운 상태로 만드는 경우가 있고, 둘째로 농지에 대하여 외부적 형상 의 변경을 수반하지 않거나 외부적 형상의 변경을 수반하더라도 사회통념상 원상회복이 어려운 정 형법 총론 제 2 편 범 죄 론 도에 이르지 않은 상태에서 그 농지를 다른 목적에 사용하는 경우 등이 있을 수 있다. 전자의 경 우와 같이 농지전용행위 자체에 의하여 당해 토지가 농지로서의 기능을 상실하여 그 이후 그 토지 를 농업생산 등 외의 목적으로 사용하는 행위가 더 이상 ‘(A)’에 해당하지 않는다고 할 때 에는, 허가 없이 그와 같이 농지를 전용한 죄는 그와 같은 행위가 종료됨으로써 즉시 성립하고 그 와 동시에 완성되는 즉시범이라고 보아야 한다. 그러나 후자의 경우와 같이 당해 토지를 농업생산 등 외의 다른 목적으로 사용하는 행위를 여전히 농지전용으로 볼 수 있는 때에는 허가 없이 그와 같이 농지를 전용하는 죄는 계속범으로서 그 토지를 다른 용도로 사용하는 한 가벌적인 위법행위 가 계속 반복되고 있는 계속범이라고 보아야 한다. → 농지에 잡석 등을 깔아 정지작업이 이루어져 사실상 원상회복이 어렵게 된 토지를 전용하였 다는 공소사실에 대하여, 공소 범행 당시 농지로서의 현상을 상실한 토지를 사용한 것이 농지전용 죄를 구성하는지 여부를 먼저 살펴본 다음 공소시효의 기산점을 판단하여야 한다는 이유로, 정지작업 의 종료시점을 공소시효의 기산점으로 보아 공소시효가 완성되었다고 본 원심판결을 파기한 사례.','농지의 전용','형법 표준판례 15. 즉시범 대법원 2009. 4. 16. 선고 2007도6703 전원합의체 판결','','판례검색'),
(48,'헌법 표준판례 14. 정당등록요건','가. 이 사건 법률조항 중 제25조의 규정은 이른바 “지역정당”을 배제하려는 취지로 볼 수 있고, 제27조의 규정은 이른바 “(A)”을 배제하려는 취지로 볼 수 있다. 우선 우리 헌법의 대의민주 적 기본질서가 제기능을 수행하기 위해서는 의회 내의 안정된 다수세력의 확보를 필요로 한다는 점에서, 군소정당의 배제는 그 목적의 정당성이 인정될 수 있다. 또한 지역적 연고에 지나치게 의 존하는 정당정치풍토가 우리의 정치현실에서 자주 문제시되고 있다는 점에서 볼 때, 단지 특정지역 의 정치적 의사만을 반영하려는 지역정당을 배제하려는 취지가 헌법에 어긋난 입법목적이라고 단 정하기는 어렵다. 따라서 이 사건 법률조항의 입법목적은 정당한 것이라고 할 것이다.','군소정당','헌법 표준판례 14. 정당등록요건','','판례검색'),
(49,'헌법 표준판례 14. 정당등록요건','가. 이 사건 법률조항 중 제25조의 규정은 이른바 “(A)”을 배제하려는 취지로 볼 수 있고, 제27조의 규정은 이른바 “군소정당”을 배제하려는 취지로 볼 수 있다. 우선 우리 헌법의 대의민주 적 기본질서가 제기능을 수행하기 위해서는 의회 내의 안정된 다수세력의 확보를 필요로 한다는 점에서, 군소정당의 배제는 그 목적의 정당성이 인정될 수 있다. 또한 지역적 연고에 지나치게 의 존하는 정당정치풍토가 우리의 정치현실에서 자주 문제시되고 있다는 점에서 볼 때, 단지 특정지역 의 정치적 의사만을 반영하려는 지역정당을 배제하려는 취지가 헌법에 어긋난 입법목적이라고 단 정하기는 어렵다. 따라서 이 사건 법률조항의 입법목적은 정당한 것이라고 할 것이다.','지역정당','헌법 표준판례 14. 정당등록요건','','판례검색'),
(50,'민법 표준판례 28. 법인의 불법행위능력 대법원 2011. 4. 28. 선고 2008다15438 판결','제 3 5 조 제 1 항 은 “ 법 인 은 이 사 기 타 대 표 자 가 그 직 무 에 관 하 여 타 인 에 게 가 한 손 해 를 배상할 책임이 있다”라고 정한다. 여기서 ‘법인의 대표자’에는 그 명칭이나 직위 여하, 또는 대표자로 (A) 되었는지 여부를 불문하고 당해 법인을 실질적으로 운영하면서 법인을 사실상 대표하여 법인의 사 무를 집행하는 사람을 포함한다고 해석함이 상당하다. 구체적인 사안에서 이러한 사람에 해당하는 지는 법인과의 관계에서 그 지위와 역할, 법인의 사무 집행 절차와 방법, 대내적·대외적 명칭을 비 롯하여 법인 내부자와 거래 상대방에게 법인의 대표행위로 인식되는지 여부, 공부상 대표자와의 관 계 및 공부상 대표자가 법인의 사무를 집행하는지 여부 등 제반 사정을 종합적으로 고려하여 판단 하여야 한다. 그리고 이러한 법리는 주택조합과 같은 비법인사단에도 마찬가지로 적용된다.','등기','민법 표준판례 28. 법인의 불법행위능력 대법원 2011. 4. 28. 선고 2008다15438 판결','','판례검색'),
(51,'민법 표준판례 28. 법인의 불법행위능력 대법원 2011. 4. 28. 선고 2008다15438 판결','제 3 5 조 제 1 항 은 “ 법 인 은 이 사 기 타 대 표 자 가 그 직 무 에 관 하 여 타 인 에 게 가 한 손 해 를 배상할 책임이 있다”라고 정한다. 여기서 ‘(A)’에는 그 명칭이나 직위 여하, 또는 대표자로 등기 되었는지 여부를 불문하고 당해 법인을 실질적으로 운영하면서 법인을 사실상 대표하여 법인의 사 무를 집행하는 사람을 포함한다고 해석함이 상당하다. 구체적인 사안에서 이러한 사람에 해당하는 지는 법인과의 관계에서 그 지위와 역할, 법인의 사무 집행 절차와 방법, 대내적·대외적 명칭을 비 롯하여 법인 내부자와 거래 상대방에게 법인의 대표행위로 인식되는지 여부, 공부상 대표자와의 관 계 및 공부상 대표자가 법인의 사무를 집행하는지 여부 등 제반 사정을 종합적으로 고려하여 판단 하여야 한다. 그리고 이러한 법리는 주택조합과 같은 비법인사단에도 마찬가지로 적용된다.','법인의 대표자','민법 표준판례 28. 법인의 불법행위능력 대법원 2011. 4. 28. 선고 2008다15438 판결','','판례검색'),
(52,'형법 표준판례 18. 인과관계의 단절 대법원 2014. 7. 24. 선고 2014도6206 판결','형법 제188조에 규정된 교통방해에 의한 치사상죄는 결과적 가중 범이므로, 위 죄가 성립하려면 교통방해 행위와 사상의 결과 사이에 상당인과관계가 있어야 하고 행위 시에 결과의 발생을 예견 할 수 있어야 한다. 그리고 교통방해 행위가 피해자의 사상이라는 결과를 발생하게 한 유일하거나 직접적인 원인이 된 경우만이 아니라, 그 행위와 결과 사이에 피해자나 제3자의 (A) 등 다른 사 실이 개재된 때에도 그와 같은 사실이 통상 예견될 수 있는 것이라면 상당인과관계를 인정할 수 있다(대법원 1994. 3. 22. 선고 93도3612 판결 참조 ).','과실','형법 표준판례 18. 인과관계의 단절 대법원 2014. 7. 24. 선고 2014도6206 판결','','판례검색'),
(53,'헌법 표준판례 15. 정당등록취소','따라서 입법자는 정 당설립의 자유를 최대한 보장하는 방향으로 입법하여야 하고, 헌법재판소는 정당설립의 자유를 제 한하는 법률의 합헌성을 심사할 때에 헌법 제37조 제2항에 따라 엄격한 비례심사를 하여야 한다. 2. 실질적으로 국민의 정치적 의사형성에 참여할 의사나 능력이 없는 정당을 정치적 의사형성과 정에서 배제함으로써 정당제 민주주의 발전에 기여하고자 하는 한도에서 정당등록취소조항의 입법 목적의 정당성과 수단의 적합성을 인정할 수 있다. 그러나 정당등록의 취소는 정당의 존속 자체를 박탈하여 모든 형태의 정당활동을 불가능하게 하므로, 그에 대한 입법은 필요최소한의 범위에서 엄 격한 기준에 따라 이루어져야 한다. (A) 동안 공직선거에 참여할 기회를 수 회 부여 하고 그 결과에 따라 등록취소 여부를 결정하는 등 덜 기본권 제한적인 방법을 상정할 수 있고, 정당법에서 법정의 등록요건을 갖추지 못하게 된 정당이나 일정 기간 국회의원선거 등에 참여하지 아니한 정당의 등록을 취소하도록 하는 등 현재의 법체계 아래에서도 입법목적을 실현할 수 있는 다른 장치가 마련되어 있으므로, 정당등록취소조항은 침해의 최소성 요건을 갖추지 못하였다.','그런데 일정기간','헌법 표준판례 15. 정당등록취소','','판례검색'),
(54,'민법 표준판례 29. 법인의 불법행위능력 대법원 1999. 7. 27. 선고 99다19384 판결','도시재개발법에 의하여 설립된 재개발조합의 조합원이 조합의 이사 기타 조합장 등 대표기관의 직무상의 불법행위로 인하여 직접 손해를 입은 경우에는 도시재개발법 제21조, 제35조에 의하여 재개발조합에 대하여 그 손해배상을 청구할 수 있으나, 재개발조합의 대표기관의 직무상 (A) 로 조합에게 과다한 채무를 부담하게 함으로써 재개발조합이 손해를 입고 결과적으로 조합원의 경 제적 이익이 침해되는 손해와 같은 간접적인 손해는 제35조에서 말하는 손해의 개념에 포함되지 아니하므로 이에 대하여는 위 법 조항에 의하여 손해배상을 청구할 수 없다.','불법행위','민법 표준판례 29. 법인의 불법행위능력 대법원 1999. 7. 27. 선고 99다19384 판결','','판례검색'),
(55,'민법 표준판례 29. 법인의 불법행위능력 대법원 1999. 7. 27. 선고 99다19384 판결','도시재개발법에 의하여 설립된 재개발조합의 조합원이 조합의 이사 기타 조합장 등 대표기관의 직무상의 불법행위로 인하여 직접 손해를 입은 경우에는 도시재개발법 제21조, 제35조에 의하여 재개발조합에 대하여 그 손해배상을 청구할 수 있으나, 재개발조합의 (A) 로 조합에게 과다한 채무를 부담하게 함으로써 재개발조합이 손해를 입고 결과적으로 조합원의 경 제적 이익이 침해되는 손해와 같은 간접적인 손해는 제35조에서 말하는 손해의 개념에 포함되지 아니하므로 이에 대하여는 위 법 조항에 의하여 손해배상을 청구할 수 없다.','대표기관의 직무상 불법행위','민법 표준판례 29. 법인의 불법행위능력 대법원 1999. 7. 27. 선고 99다19384 판결','','판례검색'),
(56,'형법 표준판례 18. 인과관계의 단절 대법원 2014. 7. 24. 선고 2014도6206 판결','22. 선고 93도3612 판결 참조 ). → 제1심은, ‘이 사건 당시 1·2차로에 차량들이 정상 속도로 꾸준히 진행하고 있어 1차로에 갑자 기 차량을 세울 경우 1차로를 진행하던 차량들이 미처 이를 피하지 못하고 추돌하여 대형사고로 이어질 수 있는 상황임에도, 피고인은 2차로를 따라 시속 110~120km 정도로 진행하여 1 차로를 진행하던 피해자 공소외 1의 차량 앞에 급하게 끼어든 후 곧바로 제동하여 약 6초 만에 정차하였 고, 뒤따르던 피해자 공소외 1의 차량과 이어서 승용차 한 대 및 트럭 한 대는 급하게 제동하여 정차하였으나, 그 뒤에 따라오던 피해자 공소외 2가 운전하는 5톤 카고트럭은 이를 피하거나 정차 하지 못하고 피고인 차량 정차 후 약 5~6초 만에 앞서 정차하여 있는 맨 뒤의 트럭을 들이받아 그 충격으로 차량들이 차례로 앞으로 밀리면서 연쇄적으로 충돌한 사고를 발생시켜, 피해자 공소외 2를 사망에 이르게 하고 나머지 차량 운전자 등 피해자들에게 상해를 입혔다’는 이 사건 일반교통 방해치사상의 공소사실에 관하여, 피해자 공소외 2가 주의의무를 다하지 못한 과실이 있다고 섣불 리 인정하기도 어려운 데다가, 설령 피해자 공소외 2에게 주의의무를 위반한 과실이 있다 하더라 도 그러한 사정만으로 피고인의 일반교통방해의 범행과 피해자들의 사상의 (A) 가 단절되었다고 볼 수 없고, 피고인의 진술 등에 비추어 피고인에게 그 결과 발생에 대한 예견가 능성도 있다는 이유로 이를 유죄로 인정하였고, 대법원은 그 판단이 정당하다고 본 판례.','결과 사이에 인과관계','형법 표준판례 18. 인과관계의 단절 대법원 2014. 7. 24. 선고 2014도6206 판결','','판례검색'),
(57,'헌법 표준판례 15. 정당등록취소','그러나 정당등록의 취소는 정당의 존속 자체를 박탈하여 모든 형태의 정당활동을 불가능하게 하므로, 그에 대한 입법은 필요최소한의 범위에서 엄 격한 기준에 따라 이루어져야 한다. (A) 동안 공직선거에 참여할 기회를 수 회 부여 하고 그 결과에 따라 등록취소 여부를 결정하는 등 덜 기본권 제한적인 방법을 상정할 수 있고, 정당법에서 법정의 등록요건을 갖추지 못하게 된 정당이나 일정 기간 국회의원선거 등에 참여하지 아니한 정당의 등록을 취소하도록 하는 등 현재의 법체계 아래에서도 입법목적을 실현할 수 있는 다른 장치가 마련되어 있으므로, 정당등록취소조항은 침해의 최소성 요건을 갖추지 못하였다. 나아 가, 정당등록취소조항은 어느 정당이 대통령선거나 지방자치선거에서 아무리 좋은 성과를 올리더라 도 국회의원선거에서 일정 수준의 지지를 얻는 데 실패하면 등록이 취소될 수밖에 없어 불합리하 고, 신생·군소정당으로 하여금 국회의원선거에의 참여 자체를 포기하게 할 우려도 있어 법익의 균 형성 요건도 갖추지 못하였다. 따라서 정당등록취소조항은 과잉금지원칙에 위반되어 청구인들의 정 당설립의 자유를 침해한다. 3.','그런데 일정기간','헌법 표준판례 15. 정당등록취소','','판례검색'),
(58,'민법 표준판례 31. 법인의 불법행위능력 대법원 1998. 11. 10. 선고 98다34126 판결','법인의 경우 불법행위로 인한 손해배상청구권의 단기 소멸시효의 기산점인 ‘(A)’이라 함은 통상 대표자가 이를 안 날을 뜻하지만, 법인의 대표자가 가해자에 가담하여 법인 에 대하여 공동불법행위가 성립하는 경우에는, 법인과 그 대표자는 이익이 상반하게 되므로 현실로 그로 인한 손해배상청구권을 행사하리라고 기대하기 어려울 뿐만 아니라 일반적으로 그 대표권도 부인된다고 할 것이므로, 단지 그 대표자가 손해 및 가해자를 아는 것만으로는 부족하고, 적어도 법인의 이익을 정당하게 보전할 권한을 가진 다른 임원 또는 사원이나 직원 등이 손해배상청구권 을 행사할 수 있을 정도로 이를 안 때에 비로소 위 단기시효가 진행한다고 해석함이 상당하다.','손해 및 가해자를 안 날','민법 표준판례 31. 법인의 불법행위능력 대법원 1998. 11. 10. 선고 98다34126 판결','','판례검색'),
(59,'민법 표준판례 31. 법인의 불법행위능력 대법원 1998. 11. 10. 선고 98다34126 판결','법인의 경우 불법행위로 인한 손해배상청구권의 단기 소멸시효의 기산점인 ‘손해 및 가해자를 안 날’이라 함은 통상 대표자가 이를 안 날을 뜻하지만, 법인의 대표자가 가해자에 가담하여 법인 에 대하여 공동불법행위가 성립하는 경우에는, 법인과 그 대표자는 이익이 상반하게 되므로 현실로 그로 인한 손해배상청구권을 행사하리라고 기대하기 어려울 뿐만 아니라 일반적으로 그 대표권도 부인된다고 할 것이므로, 단지 그 대표자가 손해 및 가해자를 아는 것만으로는 부족하고, 적어도 법인의 이익을 정당하게 보전할 권한을 가진 다른 임원 또는 사원이나 (A) 을 행사할 수 있을 정도로 이를 안 때에 비로소 위 단기시효가 진행한다고 해석함이 상당하다.','직원 등이 손해배상청구권','민법 표준판례 31. 법인의 불법행위능력 대법원 1998. 11. 10. 선고 98다34126 판결','','판례검색'),
(60,'형법 표준판례 19. 교사의 인과성 대법원 2012. 11. 15. 선고 2012도7407 판결','선고 91도542 판결 등 참조). … 피고인은 공소외인으로 하여금 이 사건 공갈 범죄의 실행을 결의하게 하였고, 피고인의 교사에 의하여 범죄 실행을 결의하게 된 공소외인이 그 실행행위에 나아가기 전에 피고인으로부터 범행을 만류하는 전화를 받기는 하였으나 이를 명시적으로 거절함으로써 여전히 피고인의 교사 내용과 같 은 범죄 실행의 결의를 그대로 유지하였으며, 그 결의에 따라 실제로 피해자를 공갈하였음을 알 수 있다. 이를 앞서 본 법리에 비추어 보면, 피고인의 교사행위와 (A) 사이에는 상당인과관계가 인정된다 할 것이고, 피고인의 만류행위가 있었지만 공소외인이 이를 명시적으로 거절하고 당초와 같은 범죄 실행의 결의를 그대로 유지한 것으로 보이는 이상, 피고인이 공범관계 에서 이탈한 것으로 볼 수도 없다. → 피고인의 교사행위로 인하여 공소외인이 범행의 결의를 가지게 되었고, 그 후 공갈의 실행행 위에 착수하여 피해자로부터 500만 원을 교 부받음으로써 범행이 기수에 이르렀으므로 피고인의 교 사행위와 공소외인의 범행 결의 및 실행행위 사이에 인과관계가 인정되고, 또 피고인이 전화로 범 행을 만류하는 취지의 말을 한 것만으로는 피고인의 교사행위와 공소외인의 실행행위 사이에 인과 관계가 단절되었다거나 피고인이 공범관계에서 이탈한 것으로 볼 수 없다고 하여, 피고인을 유죄로 판단한 제1심판결을 그대로 유지하였고, 대법원은 법리오해의 위법이 없다고 판단한 사건이다.','공소외인의 공갈행위','형법 표준판례 19. 교사의 인과성 대법원 2012. 11. 15. 선고 2012도7407 판결','','판례검색'),
(61,'형법 표준판례 19. 교사의 인과성 대법원 2012. 11. 15. 선고 2012도7407 판결','선고 91도542 판결 등 참조). … 피고인은 공소외인으로 하여금 이 사건 공갈 범죄의 실행을 결의하게 하였고, 피고인의 교사에 의하여 범죄 실행을 결의하게 된 공소외인이 그 실행행위에 나아가기 전에 피고인으로부터 범행을 만류하는 전화를 받기는 하였으나 이를 명시적으로 거절함으로써 여전히 피고인의 교사 내용과 같 은 범죄 실행의 결의를 그대로 유지하였으며, 그 결의에 따라 실제로 피해자를 공갈하였음을 알 수 있다. 이를 앞서 본 법리에 비추어 보면, 피고인의 교사행위와 공소외인의 공갈행위 사이에는 상당인과관계가 인정된다 할 것이고, 피고인의 만류행위가 있었지만 공소외인이 이를 명시적으로 거절하고 당초와 같은 범죄 실행의 결의를 그대로 유지한 것으로 보이는 이상, 피고인이 공범관계 에서 이탈한 것으로 볼 수도 없다. → 피고인의 교사행위로 인하여 공소외인이 범행의 결의를 가지게 되었고, 그 후 공갈의 실행행 위에 착수하여 피해자로부터 500만 원을 교 부받음으로써 범행이 기수에 이르렀으므로 피고인의 교 사행위와 공소외인의 범행 결의 및 실행행위 사이에 인과관계가 인정되고, 또 피고인이 전화로 범 행을 만류하는 취지의 말을 한 것만으로는 피고인의 교사행위와 (A) 사이에 인과 관계가 단절되었다거나 피고인이 공범관계에서 이탈한 것으로 볼 수 없다고 하여, 피고인을 유죄로 판단한 제1심판결을 그대로 유지하였고, 대법원은 법리오해의 위법이 없다고 판단한 사건이다.','공소외인의 실행행위','형법 표준판례 19. 교사의 인과성 대법원 2012. 11. 15. 선고 2012도7407 판결','','판례검색'),
